        "inline bool applyHookOverride(lua_State* L, int valueIdx, lua_CFunction fn, void* ctx, char const* targetId) {\n"
        "    auto* host = luax::BindingHost::fromState(L);\n"
        "    if (!host) {\n"
        '        geode::log::error("luau hook [{}] override rejected: binding host unavailable", targetId);\n'
        "        return false;\n"
        "    }\n"
        "    int top = lua_gettop(L);\n"
        "    int absValue = normalizeLuaIndex(L, valueIdx);\n"
        "    lua_pushlightuserdata(L, ctx);\n"
        "    lua_pushcclosure(L, fn, nullptr, 1);\n"
