        "        return false;\n"
        "    }\n"
        "    lua_settop(L, top);\n"
        "    return true;\n"
        "}\n\n"
        "inline void adoptMacHookThread() {\n"
        "#if defined(GEODE_IS_MACOS)\n"
        "    if (!luax::Runtime::isMainThread()) {\n"
        "        luax::Runtime::setMainThreadId(std::this_thread::get_id());\n"
        "    }\n"
        "#endif\n"
        "}\n\n"
        "template <class PushContext, class ApplyArgs, class ApplySkip>\n"
        "bool runLuaPreHooks(char const* targetId, int nargs, PushContext pushContext, ApplyArgs applyArgs, ApplySkip applySkip) {\n"
        "    adoptMacHookThread();\n"
        "    auto it = hookStates().find(targetId);\n"
